// Function to test
async function fetchUserData(userId: string): Promise<{ id: string; name: string }> {
  const response = await fetch(`/api/users/${userId}`);
  if (!response.ok) throw new Error('Failed to fetch user');
  return response.json();
}

// Jest tests
describe('fetchUserData', () => {
  beforeEach(() => {
    global.fetch = jest.fn();
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  test('should fetch user data successfully', async () => {
    const mockData = { id: '123', name: 'John Doe' };
    (global.fetch as jest.Mock).mockResolvedValueOnce({
      ok: true,
      json: async () => mockData,
    });

    const result = await fetchUserData('123');
    expect(result).toEqual(mockData);
    expect(global.fetch).toHaveBeenCalledWith('/api/users/123');
  });

  test('should throw error when API returns non-ok status', async () => {
    (global.fetch as jest.Mock).mockResolvedValueOnce({
      ok: false,
    });

    await expect(fetchUserData('invalid')).rejects.toThrow('Failed to fetch user');
  });

  test('should throw error when fetch fails', async () => {
    (global.fetch as jest.Mock).mockRejectedValueOnce(new Error('Network error'));

    await expect(fetchUserData('123')).rejects.toThrow('Network error');
  });
});

description.en:
Write unit tests for a UserService that depends on a Logger module. You need to mock the Logger dependency and verify it's called correctly.

**Requirements:**
- Mock the Logger module to track calls
- Test UserService methods that use Logger
- Verify correct log messages are called
- Test that Logger methods are invoked with correct parameters
- Cover at least 3 test cases

**Module structure:**
typescript
// logger.ts
export const logger = {
  info: (message: string) => console.log(message),
  error: (message: string) => console.error(message),
};

// userService.ts
import { logger } from './logger';

export class UserService {
  createUser(name: string): void {
    logger.info(`Creating user: ${name}`);
    // user creation logic
  }

  deleteUser(id: string): void {
    logger.info(`Deleting user: ${id}`);
    // user deletion logic
  }
}


**Example:**
- createUser('Alice') → logs 'Creating user: Alice'
- deleteUser('123') → logs 'Deleting user: 123'

