    expect(logger.info).toHaveBeenNthCalledWith(1, 'Creating user: Bob');
    expect(logger.info).toHaveBeenNthCalledWith(2, 'Deleting user: 456');
  });
});

description.en:
Write comprehensive tests for a React component that fetches user data on mount and handles user interactions. The component should display a loading state, handle errors, and update the UI when data arrives.

**Requirements:**
- Use React Testing Library (RTL) for testing
- Test user interactions with userEvent (not fireEvent)
- Test async state updates with waitFor
- Verify loading states and error messages
- Ensure proper cleanup of effects

**Component behavior:**
typescript
interface UserCardProps {
  userId: string;
}

interface User {
  id: string;
  name: string;
  email: string;
}

const UserCard: React.FC<UserCardProps> = ({ userId }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetchUser(userId).then(setUser).catch(e => setError(e.message)).finally(() => setLoading(false));
  }, [userId]);

  if (loading) return <div>Loading...</div>;
  if (error) return <div role="alert">{error}</div>;
  return user ? <div><h2>{user.name}</h2><p>{user.email}</p></div> : null;
};


**Example:**
- Render component with userId="123"
- Initially shows "Loading..."
- After API call completes, displays user name and email
- If API fails, shows error message with role="alert"

