import { render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { UserCard } from './UserCard';

jest.mock('./api', () => ({
  fetchUser: jest.fn(),
}));

import { fetchUser } from './api';

describe('UserCard', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should display loading state initially', () => {
    (fetchUser as jest.Mock).mockImplementation(() => new Promise(() => {}));
    render(<UserCard userId="123" />);
    expect(screen.getByText('Loading...')).toBeInTheDocument();
  });

  it('should display user data after successful fetch', async () => {
    const mockUser = { id: '123', name: 'John Doe', email: 'john@example.com' };
    (fetchUser as jest.Mock).mockResolvedValue(mockUser);
    render(<UserCard userId="123" />);
    expect(screen.getByText('Loading...')).toBeInTheDocument();
    await waitFor(() => {
      expect(screen.getByText('John Doe')).toBeInTheDocument();
      expect(screen.getByText('john@example.com')).toBeInTheDocument();
    });
  });

  it('should display error message on fetch failure', async () => {
    const errorMessage = 'Failed to fetch user';
    (fetchUser as jest.Mock).mockRejectedValue(new Error(errorMessage));
    render(<UserCard userId="123" />);
    expect(screen.getByText('Loading...')).toBeInTheDocument();
    await waitFor(() => {
      expect(screen.getByRole('alert')).toHaveTextContent(errorMessage);
    });
  });

  it('should refetch when userId prop changes', async () => {
    const mockUser1 = { id: '123', name: 'John', email: 'john@example.com' };
    const mockUser2 = { id: '456', name: 'Jane', email: 'jane@example.com' };
    (fetchUser as jest.Mock).mockResolvedValueOnce(mockUser1);
    const { rerender } = render(<UserCard userId="123" />);
    await waitFor(() => expect(screen.getByText('John')).toBeInTheDocument());
    (fetchUser as jest.Mock).mockResolvedValueOnce(mockUser2);
    rerender(<UserCard userId="456" />);
    await waitFor(() => expect(screen.getByText('Jane')).toBeInTheDocument());
    expect(fetchUser).toHaveBeenCalledTimes(2);
  });
});

description.en:
