import { renderHook, act } from '@testing-library/react';
import { useForm } from './useForm';

describe('useForm Hook', () => {
  const mockOnSubmit = jest.fn();
  const mockValidate = jest.fn((values) => ({}));

  const initialValues = { email: '', password: '' };
  const options = {
    initialValues,
    validate: mockValidate,
    onSubmit: mockOnSubmit,
  };

  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should initialize with provided values', () => {
    const { result } = renderHook(() => useForm(options));
    expect(result.current.values).toEqual(initialValues);
    expect(result.current.errors).toEqual({});
    expect(result.current.isSubmitting).toBe(false);
  });

  it('should update values on handleChange', () => {
    const { result } = renderHook(() => useForm(options));
    act(() => {
      result.current.handleChange({
        target: { name: 'email', value: 'test@example.com' },
      } as React.ChangeEvent<HTMLInputElement>);
    });
    expect(result.current.values.email).toBe('test@example.com');
  });

  it('should validate on submit and show errors', async () => {
    mockValidate.mockReturnValue({ email: 'Email is required' });
    const { result } = renderHook(() => useForm(options));
    await act(async () => {
      await result.current.handleSubmit({
        preventDefault: jest.fn(),
      } as unknown as React.FormEvent);
    });
    expect(result.current.errors).toEqual({ email: 'Email is required' });
    expect(mockOnSubmit).not.toHaveBeenCalled();
  });

  it('should call onSubmit when validation passes', async () => {
    mockValidate.mockReturnValue({});
    const { result } = renderHook(() => useForm(options));
    act(() => {
      result.current.handleChange({
        target: { name: 'email', value: 'test@example.com' },
      } as React.ChangeEvent<HTMLInputElement>);
    });
    await act(async () => {
      await result.current.handleSubmit({
        preventDefault: jest.fn(),
      } as unknown as React.FormEvent);
    });
    expect(mockOnSubmit).toHaveBeenCalledWith({ email: 'test@example.com', password: '' });
  });

  it('should reset values and errors', () => {
    const { result } = renderHook(() => useForm(options));
    act(() => {
      result.current.handleChange({
        target: { name: 'email', value: 'test@example.com' },
      } as React.ChangeEvent<HTMLInputElement>);
    });
    act(() => {
      result.current.reset();
    });
    expect(result.current.values).toEqual(initialValues);
    expect(result.current.errors).toEqual({});
  });

  it('should track isSubmitting state during async submit', async () => {
    mockValidate.mockReturnValue({});
    mockOnSubmit.mockImplementation(() => new Promise((resolve) => setTimeout(resolve, 100)));
    const { result } = renderHook(() => useForm(options));
    const submitPromise = act(async () => {
      await result.current.handleSubmit({
        preventDefault: jest.fn(),
      } as unknown as React.FormEvent);
    });
    expect(result.current.isSubmitting).toBe(true);
    await submitPromise;
    expect(result.current.isSubmitting).toBe(false);
  });
});

description.en:
Write an integration test for a complete form submission flow wrapped in an error boundary. The test should verify successful submission, API error handling, and error boundary display when components crash.

**Requirements:**
- Test complete user flow from form input to submission
- Mock API responses with MSW (Mock Service Worker) pattern concepts
- Verify error boundary catches component errors
- Test recovery mechanisms and retry logic
- Use screen queries and proper async handling

**Components involved:**
typescript
// ErrorBoundary component
class ErrorBoundary extends React.Component {
  state = { hasError: false };
  static getDerivedStateFromError() { return { hasError: true }; }
  render() {
    if (this.state.hasError) {
      return <div role="alert">Something went wrong!</div>;
    }
    return this.props.children;
  }
}

// LoginForm component
const LoginForm = () => {
  const { values, handleChange, handleSubmit } = useForm({
    initialValues: { username: '', password: '' },
    validate: (v) => ({ ...validationErrors }),
    onSubmit: async (v) => { await loginAPI(v); }
  });
  return (
    <form onSubmit={handleSubmit}>
      <input name="username" value={values.username} onChange={handleChange} />
      <input name="password" value={values.password} onChange={handleChange} />
      <button type="submit">Login</button>
    </form>
  );
};


**Test scenarios:**
- User fills form and submits successfully
- API returns error, form shows error message
- Component throws error, boundary catches it
- User can retry after failure

