import { render, screen, waitFor } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { LoginForm } from './LoginForm';
import { ErrorBoundary } from './ErrorBoundary';

jest.mock('./api', () => ({
  loginAPI: jest.fn(),
}));

import { loginAPI } from './api';

const renderWithErrorBoundary = (component: React.ReactElement) => {
  return render(<ErrorBoundary>{component}</ErrorBoundary>);
};

describe('LoginForm with ErrorBoundary Integration Test', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should successfully submit form with valid credentials', async () => {
    const user = userEvent.setup();
    (loginAPI as jest.Mock).mockResolvedValue({ success: true });
    renderWithErrorBoundary(<LoginForm />);
    const usernameInput = screen.getByRole('textbox', { name: /username/i });
    const passwordInput = screen.getByLabelText(/password/i);
    const submitButton = screen.getByRole('button', { name: /login/i });
    await user.type(usernameInput, 'testuser');
    await user.type(passwordInput, 'password123');
    await user.click(submitButton);
    await waitFor(() => {
      expect(loginAPI).toHaveBeenCalledWith({ username: 'testuser', password: 'password123' });
    });
    expect(screen.queryByRole('alert')).not.toBeInTheDocument();
  });

  it('should display API error message on submission failure', async () => {
    const user = userEvent.setup();
    const errorMessage = 'Invalid credentials';
    (loginAPI as jest.Mock).mockRejectedValue(new Error(errorMessage));
    renderWithErrorBoundary(<LoginForm />);
    const usernameInput = screen.getByRole('textbox', { name: /username/i });
    const passwordInput = screen.getByLabelText(/password/i);
    const submitButton = screen.getByRole('button', { name: /login/i });
    await user.type(usernameInput, 'testuser');
    await user.type(passwordInput, 'wrongpass');
    await user.click(submitButton);
    await waitFor(() => {
      expect(screen.getByRole('alert')).toHaveTextContent(errorMessage);
    });
  });

  it('should catch component errors in error boundary', async () => {
    const ThrowError = () => {
      throw new Error('Component crashed');
    };
    // Suppress console.error for this test
    const spy = jest.spyOn(console, 'error').mockImplementation();
    renderWithErrorBoundary(<ThrowError />);
    expect(screen.getByRole('alert')).toHaveTextContent('Something went wrong');
    spy.mockRestore();
  });

  it('should allow user to retry after error', async () => {
    const user = userEvent.setup();
    (loginAPI as jest.Mock).mockRejectedValueOnce(new Error('Network error')).mockResolvedValueOnce({ success: true });
    renderWithErrorBoundary(<LoginForm />);
    const usernameInput = screen.getByRole('textbox', { name: /username/i });
    const passwordInput = screen.getByLabelText(/password/i);
    const submitButton = screen.getByRole('button', { name: /login/i });
    // First attempt fails
    await user.type(usernameInput, 'testuser');
    await user.type(passwordInput, 'password123');
    await user.click(submitButton);
    await waitFor(() => {
      expect(screen.getByRole('alert')).toHaveTextContent('Network error');
    });
    // Second attempt succeeds
    await user.click(submitButton);
    await waitFor(() => {
      expect(screen.queryByRole('alert')).not.toBeInTheDocument();
    });
    expect(loginAPI).toHaveBeenCalledTimes(2);
  });

  it('should validate form before submission', async () => {
    const user = userEvent.setup();
    renderWithErrorBoundary(<LoginForm />);
    const submitButton = screen.getByRole('button', { name: /login/i });
    await user.click(submitButton);
    await waitFor(() => {
      expect(screen.getByText(/username is required/i)).toBeInTheDocument();
      expect(screen.getByText(/password is required/i)).toBeInTheDocument();
    });
    expect(loginAPI).not.toHaveBeenCalled();
  });
});

