import { renderHook, act } from '@testing-library/react';
import { useUserForm } from './useUserForm';

describe('useUserForm Hook', () => {
  test('should initialize with default state', () => {
    const { result } = renderHook(() => useUserForm());

    expect(result.current.formState.values).toEqual({
      name: '',
      email: '',
      password: ''
    });
    expect(result.current.formState.errors).toEqual({});
    expect(result.current.formState.isDirty).toBe(false);
    expect(result.current.formState.isSubmitting).toBe(false);
  });

  test('should initialize with provided values', () => {
    const initialValues = { name: 'John', email: 'john@example.com' };
    const { result } = renderHook(() => useUserForm(initialValues));

    expect(result.current.formState.values.name).toBe('John');
    expect(result.current.formState.values.email).toBe('john@example.com');
    expect(result.current.formState.values.password).toBe('');
  });

  test('should update field value and mark form as dirty', () => {
    const { result } = renderHook(() => useUserForm());

    act(() => {
      result.current.setFieldValue('name', 'Jane Doe');
    });

    expect(result.current.formState.values.name).toBe('Jane Doe');
    expect(result.current.formState.isDirty).toBe(true);
  });

  test('should validate email field format', () => {
    const { result } = renderHook(() => useUserForm());

    act(() => {
      result.current.setFieldValue('email', 'invalid-email');
    });

    expect(result.current.formState.errors.email).toBe('Invalid email format');

    act(() => {
      result.current.setFieldValue('email', 'valid@example.com');
    });

    expect(result.current.formState.errors.email).toBeUndefined();
  });

  test('should validate password strength', () => {
    const { result } = renderHook(() => useUserForm());

    act(() => {
      result.current.setFieldValue('password', '123');
    });

    expect(result.current.formState.errors.password).toBe(
      'Password must be at least 8 characters'
    );

    act(() => {
      result.current.setFieldValue('password', 'SecurePass123!');
    });

    expect(result.current.formState.errors.password).toBeUndefined();
  });

  test('should reset form to initial state', () => {
    const { result } = renderHook(() => useUserForm());

    act(() => {
      result.current.setFieldValue('name', 'John');
      result.current.setFieldValue('email', 'john@example.com');
    });

    expect(result.current.formState.isDirty).toBe(true);

    act(() => {
      result.current.resetForm();
    });

    expect(result.current.formState.values).toEqual({
      name: '',
      email: '',
      password: ''
    });
    expect(result.current.formState.isDirty).toBe(false);
    expect(result.current.formState.errors).toEqual({});
  });

  test('should handle form submission with loading state', async () => {
    const { result } = renderHook(() => useUserForm());
    const mockCallback = jest.fn(() => Promise.resolve());

    act(() => {
      result.current.setFieldValue('name', 'John');
      result.current.setFieldValue('email', 'john@example.com');
      result.current.setFieldValue('password', 'SecurePass123!');
    });

    const submitPromise = act(() =>
      result.current.submitForm(mockCallback)
    );

    expect(result.current.formState.isSubmitting).toBe(true);

    await submitPromise;

    expect(result.current.formState.isSubmitting).toBe(false);
    expect(mockCallback).toHaveBeenCalledWith({
      name: 'John',
      email: 'john@example.com',
      password: 'SecurePass123!'
    });
  });

  test('should handle submission error gracefully', async () => {
    const { result } = renderHook(() => useUserForm());
    const error = new Error('Network error');
    const mockCallback = jest.fn(() => Promise.reject(error));

    act(() => {
      result.current.setFieldValue('name', 'John');
    });

    await expect(
      act(() => result.current.submitForm(mockCallback))
    ).rejects.toThrow('Network error');

    expect(result.current.formState.isSubmitting).toBe(false);
  });

  test('should handle multiple field updates correctly', () => {
    const { result } = renderHook(() => useUserForm());

    act(() => {
      result.current.setFieldValue('name', 'Jane');
      result.current.setFieldValue('email', 'jane@example.com');
      result.current.setFieldValue('password', 'SecurePass123!');
    });

    expect(result.current.formState.values).toEqual({
      name: 'Jane',
      email: 'jane@example.com',
      password: 'SecurePass123!'
    });
    expect(result.current.formState.isDirty).toBe(true);
    expect(result.current.formState.errors).toEqual({});
  });
});

