import { describe, it, expect, beforeEach, vi } from 'vitest';

class TrafficLight {
  private state: 'RED' | 'GREEN' | 'YELLOW' = 'RED';
  private history: string[] = ['RED'];
  private callbacks: Set<(state: string) => void> = new Set();

  get currentState() {
    return this.state;
  }

  transition(duration?: number): void {
    const transitions: Record<string, 'RED' | 'GREEN' | 'YELLOW'> = {
      'RED': 'GREEN',
      'GREEN': 'YELLOW',
      'YELLOW': 'RED'
    };

    const nextState = transitions[this.state];
    this.state = nextState;
    this.history.push(nextState);
    this.callbacks.forEach(cb => cb(nextState));
  }

  reset(): void {
    this.state = 'RED';
    this.history = ['RED'];
  }

  getHistory(): string[] {
    return [...this.history];
  }

  onStateChange(callback: (state: string) => void): void {
    this.callbacks.add(callback);
  }
}

describe('TrafficLight State Machine', () => {
  let light: TrafficLight;

  beforeEach(() => {
    light = new TrafficLight();
  });

  describe('Initialization and Basic Transitions', () => {
    it('should initialize to RED state', () => {
      expect(light.currentState).toBe('RED');
    });

    it('should have RED in initial history', () => {
      expect(light.getHistory()).toEqual(['RED']);
    });

    it('should transition RED → GREEN → YELLOW → RED', () => {
      light.transition();
      expect(light.currentState).toBe('GREEN');
      light.transition();
      expect(light.currentState).toBe('YELLOW');
      light.transition();
      expect(light.currentState).toBe('RED');
    });
  });

  describe('State History', () => {
    it('should track full transition history', () => {
      light.transition();
      light.transition();
      light.transition();
      expect(light.getHistory()).toEqual(['RED', 'GREEN', 'YELLOW', 'RED']);
    });

    it('should return independent copy of history', () => {
      const history1 = light.getHistory();
      light.transition();
      const history2 = light.getHistory();
      expect(history1).toEqual(['RED']);
      expect(history2).toEqual(['RED', 'GREEN']);
    });
  });

  describe('Reset Functionality', () => {
    it('should reset state to RED', () => {
      light.transition();
      light.transition();
      light.reset();
      expect(light.currentState).toBe('RED');
    });

    it('should clear history on reset', () => {
      light.transition();
      light.transition();
      light.reset();
      expect(light.getHistory()).toEqual(['RED']);
    });
  });

  describe('State Change Callbacks', () => {
    it('should call callback when state changes', () => {
      const callback = vi.fn();
      light.onStateChange(callback);
      light.transition();
      expect(callback).toHaveBeenCalledWith('GREEN');
    });

    it('should call multiple callbacks on state change', () => {
      const callback1 = vi.fn();
      const callback2 = vi.fn();
      light.onStateChange(callback1);
      light.onStateChange(callback2);
      light.transition();
      expect(callback1).toHaveBeenCalledWith('GREEN');
      expect(callback2).toHaveBeenCalledWith('GREEN');
    });

    it('should pass correct state to callback', () => {
      const callback = vi.fn();
      light.onStateChange(callback);
      light.transition();
      light.transition();
      light.transition();
      expect(callback).toHaveBeenNthCalledWith(1, 'GREEN');
      expect(callback).toHaveBeenNthCalledWith(2, 'YELLOW');
      expect(callback).toHaveBeenNthCalledWith(3, 'RED');
    });

    it('should call callback with duration parameter', () => {
      const callback = vi.fn();
      light.onStateChange(callback);
      light.transition(5000);
      expect(callback).toHaveBeenCalledWith('GREEN');
    });
  });

  describe('Complex State Machine Scenarios', () => {
    it('should handle rapid consecutive transitions', () => {
      for (let i = 0; i < 10; i++) {
        light.transition();
      }
      expect(light.currentState).toBe('GREEN');
      expect(light.getHistory().length).toBe(11);
    });

    it('should maintain correct sequence after reset and new transitions', () => {
      light.transition();
      light.transition();
      light.reset();
      light.transition();
      light.transition();
      expect(light.getHistory()).toEqual(['RED', 'GREEN', 'YELLOW', 'RED', 'GREEN', 'YELLOW']);
    });

    it('should call callbacks only after successful transition', () => {
      const callback = vi.fn();
      light.onStateChange(callback);
      expect(callback).not.toHaveBeenCalled();
      light.transition();
      expect(callback).toHaveBeenCalledTimes(1);
    });
  });
});

description.en:
Write property-based tests using fast-check to verify invariants of a custom data structure: a SortedArray that maintains elements in sorted order.

**Class Interface:**
typescript
class SortedArray<T> {
  constructor(compareFn?: (a: T, b: T) => number);
  add(value: T): void;
  remove(value: T): boolean;
  toArray(): T[];
  indexOf(value: T): number;
  length: number;
}


**Properties to Test:**
1. **Ordering Invariant**: After any sequence of add/remove operations, elements must remain sorted
2. **Length Invariant**: Length must match actual array size
3. **IndexOf Consistency**: indexOf should match actual position or -1
4. **Add-Remove Idempotence**: Adding then removing value returns to previous state
5. **Duplicate Handling**: Duplicate elements should be allowed
6. **Custom Comparator**: Must respect custom comparison functions

**Example:**

const arr = new SortedArray<number>((a, b) => a - b);
arr.add(5);
arr.add(2);
arr.add(8);
arr.toArray(); // [2, 5, 8]
arr.indexOf(5); // 1
arr.remove(5); // true
arr.toArray(); // [2, 8]


**Edge Cases:**
- Empty array operations
- Single element
- Duplicate values
- Negative numbers
- String comparisons with custom locale
- Large datasets (100+ elements)

