  }

  add(value: T): void {
    const insertIndex = this.elements.findIndex(el => this.compareFn(value, el) < 0);
    if (insertIndex === -1) {
      this.elements.push(value);
    } else {
      this.elements.splice(insertIndex, 0, value);
    }
  }

  remove(value: T): boolean {
    const index = this.elements.findIndex(el => this.compareFn(value, el) === 0);
    if (index !== -1) {
      this.elements.splice(index, 1);
      return true;
    }
    return false;
  }

  toArray(): T[] {
    return [...this.elements];
  }

  indexOf(value: T): number {
    return this.elements.findIndex(el => this.compareFn(value, el) === 0);
  }

  get length(): number {
    return this.elements.length;
  }
}

function isSorted<T>(arr: T[], compareFn: (a: T, b: T) => number): boolean {
  for (let i = 1; i < arr.length; i++) {
    if (compareFn(arr[i - 1], arr[i]) > 0) return false;
  }
  return true;
}

describe('SortedArray Property-Based Tests', () => {
  const numComparator = (a: number, b: number) => a - b;
  const strComparator = (a: string, b: string) => a.localeCompare(b);

  describe('Ordering Invariant', () => {
    it('should maintain sorted order after random additions', () => {
      fc.assert(
        fc.property(fc.array(fc.integer()), (numbers) => {
          const arr = new SortedArray<number>(numComparator);
          numbers.forEach(num => arr.add(num));
          expect(isSorted(arr.toArray(), numComparator)).toBe(true);
        }),
        { numRuns: 100 }
      );
    });

    it('should maintain sorted order after add and remove operations', () => {
      fc.assert(
        fc.property(
          fc.array(fc.integer()),
          fc.array(fc.integer()),
          (toAdd, toRemove) => {
            const arr = new SortedArray<number>(numComparator);
            toAdd.forEach(num => arr.add(num));
            toRemove.forEach(num => arr.remove(num));
            expect(isSorted(arr.toArray(), numComparator)).toBe(true);
          }
        ),
        { numRuns: 100 }
      );
    });

    it('should work with strings and custom comparator', () => {
      fc.assert(
        fc.property(fc.array(fc.string()), (strings) => {
          const arr = new SortedArray<string>(strComparator);
          strings.forEach(str => arr.add(str));
          expect(isSorted(arr.toArray(), strComparator)).toBe(true);
        }),
        { numRuns: 100 }
      );
    });
  });

  describe('Length Invariant', () => {
    it('should have correct length after additions', () => {
      fc.assert(
        fc.property(fc.array(fc.integer()), (numbers) => {
          const arr = new SortedArray<number>(numComparator);
          numbers.forEach(num => arr.add(num));
          expect(arr.length).toBe(arr.toArray().length);
        }),
        { numRuns: 100 }
      );
    });

    it('should decrease length correctly on remove', () => {
      fc.assert(
        fc.property(fc.array(fc.integer()), (numbers) => {
          const arr = new SortedArray<number>(numComparator);
          numbers.forEach(num => arr.add(num));
          const initialLength = arr.length;
          const uniqueValues = [...new Set(numbers)];
          let removedCount = 0;
          uniqueValues.forEach(val => {
            if (arr.remove(val)) removedCount++;
          });
          expect(arr.length).toBe(initialLength - removedCount);
        }),
        { numRuns: 100 }
      );
    });
  });

  describe('IndexOf Consistency', () => {
    it('indexOf should return correct position for added elements', () => {
      fc.assert(
        fc.property(fc.array(fc.integer({ min: 0, max: 100 })), (numbers) => {
          const arr = new SortedArray<number>(numComparator);
          numbers.forEach(num => arr.add(num));
          const sorted = arr.toArray();
          numbers.forEach(num => {
            const index = arr.indexOf(num);
            if (index !== -1) {
              expect(numComparator(sorted[index], num)).toBe(0);
            }
          });
        }),
        { numRuns: 100 }
      );
    });

    it('indexOf should return -1 for non-existent elements', () => {
      fc.assert(
        fc.property(fc.array(fc.integer({ min: 0, max: 50 })), (numbers) => {
          const arr = new SortedArray<number>(numComparator);
          numbers.forEach(num => arr.add(num));
          const nonExistent = 999;
          expect(arr.indexOf(nonExistent)).toBe(-1);
        }),
        { numRuns: 100 }
      );
    });
  });

  describe('Add-Remove Idempotence', () => {
    it('removing added element should restore previous state', () => {
      fc.assert(
        fc.property(
          fc.array(fc.integer()),
          fc.integer(),
          (numbers, value) => {
            const arr1 = new SortedArray<number>(numComparator);
            numbers.forEach(num => arr1.add(num));
            const stateBefore = arr1.toArray();

            arr1.add(value);
            arr1.remove(value);
            const stateAfter = arr1.toArray();

            expect(stateAfter).toEqual(stateBefore);
          }
        ),
        { numRuns: 100 }
      );
    });
  });

  describe('Duplicate Handling', () => {
    it('should allow duplicate values', () => {
      fc.assert(
        fc.property(fc.integer(), (value) => {
          const arr = new SortedArray<number>(numComparator);
          arr.add(value);
          arr.add(value);
          arr.add(value);
          expect(arr.length).toBe(3);
          expect(isSorted(arr.toArray(), numComparator)).toBe(true);
        }),
        { numRuns: 100 }
      );
    });
  });

  describe('Large Dataset Properties', () => {
    it('should maintain order with large number of operations', () => {
      fc.assert(
        fc.property(fc.array(fc.integer(), { minLength: 1, maxLength: 500 }), (numbers) => {
          const arr = new SortedArray<number>(numComparator);
          numbers.forEach(num => arr.add(num));
          expect(isSorted(arr.toArray(), numComparator)).toBe(true);
          expect(arr.length).toBe(arr.toArray().length);
        }),
        { numRuns: 50 }
      );
    });
  });
});

description.en:
Write tests to detect and verify handling of race conditions in an async request manager that batches requests and caches results.

**Class Interface:**
typescript
class AsyncRequestManager {
  constructor(maxConcurrent: number = 3, batchDelay: number = 10);
  request<T>(key: string, fetcher: () => Promise<T>): Promise<T>;
  clear(key?: string): void;
  getStats(): { pending: number; cached: number; failed: number };
}


**Requirements:**
1. **Deduplication**: Multiple requests with same key should return same Promise
2. **Caching**: Results should be cached and reused
3. **Batching**: Requests should be batched and sent together (configurable delay)
4. **Concurrency Control**: Max concurrent requests should be enforced
5. **Error Handling**: Failed requests should not cache and should retry
6. **Race Condition Prevention**: Clearing cache during request execution should not cause crashes

**Example Scenarios:**

const mgr = new AsyncRequestManager(2, 10);
const fetcher = () => Promise.resolve('data');

// Same requests deduplicated
const p1 = mgr.request('key1', fetcher);
const p2 = mgr.request('key1', fetcher);
await Promise.all([p1, p2]); // Both resolve with same value

// Concurrent limit respected
const promises = Array(5).fill().map(() => 
  mgr.request('unique', () => sleep(100))
);


**Race Conditions to Test:**
1. Cache cleared while request in-flight
2. Multiple requests batched together
3. Concurrent limit with slow operations
4. Error during batch processing
5. Cache invalidation during fetch
6. Timeout scenarios

description.ru:
Напишите тесты для обнаружения и проверки обработки состояний гонки в асинхронном менеджере запросов, который группирует запросы и кэширует результаты.

**Интерфейс класса:**
typescript
class AsyncRequestManager {
  constructor(maxConcurrent: number = 3, batchDelay: number = 10);
  request<T>(key: string, fetcher: () => Promise<T>): Promise<T>;
  clear(key?: string): void;
  getStats(): { pending: number; cached: number; failed: number };
}


**Требования:**
1. **Дедупликация**: Несколько запросов с одним и тем же ключом должны вернуть одно и то же Promise
2. **Кэширование**: Результаты должны кэшироваться и повторно использоваться
3. **Батчинг**: Запросы должны группироваться и отправляться вместе (настраиваемая задержка)
4. **Контроль параллелизма**: Максимум одновременных запросов должен быть обеспечен
5. **Обработка ошибок**: Неудачные запросы не должны кэшироваться и должны повторяться
6. **Предотвращение состояния гонки**: Очистка кэша во время выполнения запроса не должна вызывать сбои

**Примеры сценариев:**

const mgr = new AsyncRequestManager(2, 10);
const fetcher = () => Promise.resolve('data');

// Одни и те же запросы дедуплицированы
const p1 = mgr.request('key1', fetcher);
const p2 = mgr.request('key1', fetcher);
await Promise.all([p1, p2]); // Оба разрешаются одинаковым значением

// Соблюдается лимит параллелизма
const promises = Array(5).fill().map(() => 
  mgr.request('unique', () => sleep(100))
);


**Состояния гонки для тестирования:**
1. Кэш очищен во время передачи запроса
2. Несколько запросов обработаны вместе
3. Лимит параллелизма с медленными операциями
4. Ошибка во время обработки пакета
5. Инвалидация кэша во время выборки
6. Сценарии с истечением времени

