import { describe, it, expect, beforeEach, vi } from 'vitest';

class AsyncRequestManager {
  private cache: Map<string, Promise<any>> = new Map();
  private pending: Map<string, Promise<any>> = new Map();
  private failed: Set<string> = new Set();
  private maxConcurrent: number;
  private batchDelay: number;
  private activeCount: number = 0;
  private batchTimer: NodeJS.Timeout | null = null;
  private batchQueue: Array<{
    key: string;
    fetcher: () => Promise<any>;
    resolve: (value: any) => void;
    reject: (reason?: any) => void;
  }> = [];

  constructor(maxConcurrent: number = 3, batchDelay: number = 10) {
    this.maxConcurrent = maxConcurrent;
    this.batchDelay = batchDelay;
  }

  async request<T>(key: string, fetcher: () => Promise<T>): Promise<T> {
    // Return cached result if available
    if (this.cache.has(key)) {
      return this.cache.get(key)!;
    }

    // Return pending request if already in progress
    if (this.pending.has(key)) {
      return this.pending.get(key)!;
    }

    // Create promise for deduplication
    const promise = new Promise<T>((resolve, reject) => {
      this.batchQueue.push({ key, fetcher, resolve, reject });
      this.scheduleBatch();
    });

    this.pending.set(key, promise);
    return promise;
  }

  private scheduleBatch(): void {
    if (this.batchTimer) return;

    this.batchTimer = setTimeout(() => {
      this.processBatch();
    }, this.batchDelay);
  }

  private async processBatch(): Promise<void> {
    this.batchTimer = null;

    while (this.batchQueue.length > 0 && this.activeCount < this.maxConcurrent) {
      const batch = this.batchQueue.splice(0, this.maxConcurrent - this.activeCount);
      this.activeCount += batch.length;

      const promises = batch.map(async (item) => {
        const { key, fetcher, resolve, reject } = item;
        try {
          const result = await fetcher();
          this.cache.set(key, Promise.resolve(result));
          this.failed.delete(key);
          resolve(result);
        } catch (error) {
          this.failed.add(key);
          this.pending.delete(key);
          reject(error);
        } finally {
          this.activeCount--;
          this.pending.delete(key);
          if (this.batchQueue.length > 0 && this.activeCount < this.maxConcurrent) {
            this.processBatch();
          }
        }
      });

      await Promise.all(promises);
    }
  }

  clear(key?: string): void {
    if (key) {
      this.cache.delete(key);
      this.failed.delete(key);
    } else {
      this.cache.clear();
      this.failed.clear();
    }
  }

  getStats(): { pending: number; cached: number; failed: number } {
    return {
      pending: this.pending.size,
      cached: this.cache.size,
      failed: this.failed.size
    };
  }
}

function sleep(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

describe('AsyncRequestManager Race Conditions', () => {
  let mgr: AsyncRequestManager;

  beforeEach(() => {
    mgr = new AsyncRequestManager(2, 10);
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  describe('Deduplication', () => {
    it('should deduplicate identical requests', async () => {
      const fetcher = vi.fn(() => Promise.resolve('data'));
      const p1 = mgr.request('key1', fetcher);
      const p2 = mgr.request('key1', fetcher);
      const p3 = mgr.request('key1', fetcher);

      vi.runAllTimersAsync();
      const [r1, r2, r3] = await Promise.all([p1, p2, p3]);

      expect(r1).toBe(r2);
      expect(r2).toBe(r3);
      expect(fetcher).toHaveBeenCalledTimes(1);
    });

    it('should call fetcher once for simultaneous identical requests', async () => {
      const fetcher = vi.fn(async () => {
        await sleep(50);
        return 'result';
      });

      const promises = Array(5)
        .fill(null)
        .map(() => mgr.request('same-key', fetcher));

      vi.runAllTimersAsync();
      const results = await Promise.all(promises);

      expect(fetcher).toHaveBeenCalledTimes(1);
      expect(results).toEqual(['result', 'result', 'result', 'result', 'result']);
    });
  });

  describe('Caching', () => {
    it('should cache successful results', async () => {
      const fetcher = vi.fn(() => Promise.resolve('cached-data'));

      const r1 = await mgr.request('key', fetcher);
      vi.runAllTimersAsync();

      const r2 = await mgr.request('key', fetcher);

      expect(r1).toBe(r2);
      expect(fetcher).toHaveBeenCalledTimes(1);
      expect(mgr.getStats().cached).toBe(1);
    });

    it('should return cache without calling fetcher', async () => {
      const fetcher1 = vi.fn(() => Promise.resolve('data1'));
      const fetcher2 = vi.fn(() => Promise.resolve('data2'));

      await mgr.request('key', fetcher1);
      vi.runAllTimersAsync();

      const result = await mgr.request('key', fetcher2);

      expect(result).toBe('data1');
      expect(fetcher2).not.toHaveBeenCalled();
    });
  });

  describe('Concurrency Control', () => {
    it('should respect max concurrent limit', async () => {
      let activeCount = 0;
      let maxActive = 0;

      const fetcher = vi.fn(async () => {
        activeCount++;
        maxActive = Math.max(maxActive, activeCount);
        await sleep(50);
        activeCount--;
        return 'result';
      });

      const promises = Array(5)
        .fill(null)
        .map((_, i) => mgr.request(`key${i}`, fetcher));

      vi.runAllTimersAsync();
      await Promise.all(promises);

      expect(maxActive).toBeLessThanOrEqual(2);
    });

    it('should process queue after active requests complete', async () => {
      const callOrder: number[] = [];
      const fetcher = (id: number) =>
        vi.fn(async () => {
          callOrder.push(id);
          await sleep(50);
          return `result${id}`;
        });

      const promises = Array(4)
        .fill(null)
        .map((_, i) => mgr.request(`key${i}`, fetcher(i)));

      vi.runAllTimersAsync();
      await Promise.all(promises);

      // First batch: 2 concurrent, then second batch: 2 concurrent
      expect(callOrder.slice(0, 2).sort()).toEqual([0, 1]);
      expect(callOrder.slice(2, 4).sort()).toEqual([2, 3]);
    });
  });

  describe('Error Handling', () => {
    it('should not cache failed requests', async () => {
      const fetcher = vi.fn(() => Promise.reject(new Error('fail')));

      try {
        await mgr.request('key', fetcher);
        vi.runAllTimersAsync();
      } catch (e) {
        // expected
      }

      expect(mgr.getStats().cached).toBe(0);
      expect(mgr.getStats().failed).toBe(1);
    });

    it('should allow retry after failure', async () => {
      let callCount = 0;
      const fetcher = vi.fn(async () => {
        callCount++;
        if (callCount === 1) {
          throw new Error('first attempt fails');
        }
        return 'success';
      });

      try {
        await mgr.request('key', fetcher);
        vi.runAllTimersAsync();
      } catch (e) {
        // first call fails
      }

      const result = await mgr.request('key', fetcher);
      vi.runAllTimersAsync();

      expect(result).toBe('success');
      expect(fetcher).toHaveBeenCalledTimes(2);
    });
  });

  describe('Cache Clearing Race Conditions', () => {
    it('should handle cache clear during request', async () => {
      const fetcher = vi.fn(async () => {
        await sleep(100);
        return 'data';
      });

      const promise = mgr.request('key', fetcher);
      vi.advanceTimersByTime(10);
      mgr.clear('key');
      vi.runAllTimersAsync();

      const result = await promise;
      expect(result).toBe('data');
    });

    it('should not crash when clearing all cache', async () => {
      const fetcher = vi.fn(() => Promise.resolve('data'));

      const promises = Array(5)
        .fill(null)
        .map((_, i) => mgr.request(`key${i}`, fetcher));

      vi.advanceTimersByTime(5);
      mgr.clear();
      vi.runAllTimersAsync();

      expect(async () => {
        await Promise.all(promises);
      }).not.toThrow();
    });

    it('should allow new requests after cache clear', async () => {
      const fetcher = vi.fn(() => Promise.resolve('data'));

      await mgr.request('key', fetcher);
      vi.runAllTimersAsync();

      expect(mgr.getStats().cached).toBe(1);

      mgr.clear('key');
      expect(mgr.getStats().cached).toBe(0);

      const result = await mgr.request('key', fetcher);
      vi.runAllTimersAsync();

      expect(result).toBe('data');
      expect(fetcher).toHaveBeenCalledTimes(2);
    });
  });

  describe('Batching', () => {
    it('should batch requests within delay window', async () => {
      const fetcher = vi.fn(() => Promise.resolve('result'));

      const p1 = mgr.request('key1', fetcher);
      vi.advanceTimersByTime(5);
      const p2 = mgr.request('key2', fetcher);
      vi.advanceTimersByTime(5);
      const p3 = mgr.request('key3', fetcher);

      vi.runAllTimersAsync();
      await Promise.all([p1, p2, p3]);

      // Should be batched together due to max concurrent = 2 and batch delay
      expect(fetcher).toHaveBeenCalledTimes(3);
    });
  });

  describe('Stats', () => {
    it('should track pending, cached, and failed counts', async () => {
      const successFetcher = vi.fn(() => Promise.resolve('data'));
      const failFetcher = vi.fn(() => Promise.reject(new Error('fail')));

      const p1 = mgr.request('success', successFetcher);
      const p2 = mgr.request('fail', failFetcher);

      expect(mgr.getStats().pending).toBe(2);

      vi.runAllTimersAsync();
      await Promise.allSettled([p1, p2]);

      expect(mgr.getStats().cached).toBe(1);
      expect(mgr.getStats().failed).toBe(1);
      expect(mgr.getStats().pending).toBe(0);
    });
  });
});
